import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../contexts/AuthContext';

const AdminPanel = () => {
  const [users, setUsers] = useState([]);
  const [blogs, setBlogs] = useState([]);
  const [activeTab, setActiveTab] = useState('users');
  const [loading, setLoading] = useState(true);
  const { token } = useAuth();

  useEffect(() => {
    fetchData();
  }, [activeTab]);

  const fetchData = async () => {
    setLoading(true);
    try {
      if (activeTab === 'users') {
        const response = await axios.get('http://localhost:5000/api/admin/users', {
          headers: { Authorization: `Bearer ${token}` }
        });
        setUsers(response.data);
      } else {
        const response = await axios.get('http://localhost:5000/api/admin/all-blogs', {
          headers: { Authorization: `Bearer ${token}` }
        });
        setBlogs(response.data);
      }
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  const updateUserRole = async (userId, newRole) => {
    try {
      await axios.put(`http://localhost:5000/api/admin/users/${userId}/role`, 
        { role: newRole },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      fetchData();
    } catch (error) {
      console.error('Error updating role:', error);
    }
  };

  const deleteUser = async (userId) => {
    if (window.confirm('Are you sure you want to delete this user?')) {
      try {
        await axios.delete(`http://localhost:5000/api/admin/users/${userId}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        fetchData();
      } catch (error) {
        console.error('Error deleting user:', error);
      }
    }
  };

  const deleteBlog = async (blogId) => {
    if (window.confirm('Are you sure you want to delete this blog?')) {
      try {
        await axios.delete(`http://localhost:5000/api/admin/blogs/${blogId}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        fetchData();
      } catch (error) {
        console.error('Error deleting blog:', error);
      }
    }
  };

  const getRoleBadgeColor = (role) => {
    switch(role) {
      case 'admin': return '#ff4757';
      case 'blogger': return '#4CAF50';
      default: return '#667eea';
    }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>Admin Dashboard</h1>
      
      <div style={styles.tabs}>
        <button 
          onClick={() => setActiveTab('users')}
          style={{...styles.tab, ...(activeTab === 'users' ? styles.activeTab : {})}}
        >
          👥 Manage Users ({users.length})
        </button>
        <button 
          onClick={() => setActiveTab('blogs')}
          style={{...styles.tab, ...(activeTab === 'blogs' ? styles.activeTab : {})}}
        >
          📝 Manage Blogs ({blogs.length})
        </button>
      </div>
      
      {loading ? (
        <div style={styles.loading}>Loading...</div>
      ) : activeTab === 'users' ? (
        <div style={styles.tableContainer}>
          <table style={styles.table}>
            <thead>
              <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Role</th>
                <th>Joined</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {users.map(user => (
                <tr key={user._id}>
                  <td>{user.name}</td>
                  <td>{user.email}</td>
                  <td>
                    <select 
                      value={user.role}
                      onChange={(e) => updateUserRole(user._id, e.target.value)}
                      style={{...styles.roleSelect, backgroundColor: getRoleBadgeColor(user.role)}}
                    >
                      <option value="user">User</option>
                      <option value="blogger">Blogger</option>
                      <option value="admin">Admin</option>
                    </select>
                  </td>
                  <td>{new Date(user.createdAt).toLocaleDateString()}</td>
                  <td>
                    <button onClick={() => deleteUser(user._id)} style={styles.deleteBtn}>
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ) : (
        <div style={styles.blogList}>
          {blogs.map(blog => (
            <div key={blog._id} style={styles.blogCard}>
              <div>
                <h3 style={styles.blogTitle}>{blog.title}</h3>
                <p style={styles.blogMeta}>
                  By: {blog.author?.name || 'Unknown'} | 
                  {new Date(blog.createdAt).toLocaleDateString()}
                </p>
                <p style={styles.blogExcerpt}>{blog.content?.substring(0, 150)}...</p>
              </div>
              <button onClick={() => deleteBlog(blog._id)} style={styles.deleteBtn}>
                Delete Blog
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '40px 20px'
  },
  title: {
    fontSize: '2rem',
    color: '#333',
    marginBottom: '30px',
    textAlign: 'center'
  },
  tabs: {
    display: 'flex',
    gap: '10px',
    marginBottom: '30px',
    justifyContent: 'center'
  },
  tab: {
    padding: '12px 30px',
    background: '#e0e0e0',
    border: 'none',
    borderRadius: '25px',
    cursor: 'pointer',
    fontSize: '1rem'
  },
  activeTab: {
    background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
    color: 'white'
  },
  tableContainer: {
    overflowX: 'auto'
  },
  table: {
    width: '100%',
    borderCollapse: 'collapse',
    background: 'white',
    borderRadius: '10px',
    overflow: 'hidden'
  },
  roleSelect: {
    padding: '5px 10px',
    border: 'none',
    borderRadius: '5px',
    color: 'white',
    cursor: 'pointer'
  },
  deleteBtn: {
    padding: '5px 15px',
    background: '#ff4757',
    color: 'white',
    border: 'none',
    borderRadius: '5px',
    cursor: 'pointer'
  },
  blogList: {
    display: 'flex',
    flexDirection: 'column',
    gap: '15px'
  },
  blogCard: {
    background: 'white',
    padding: '20px',
    borderRadius: '10px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center'
  },
  blogTitle: {
    marginBottom: '10px'
  },
  blogMeta: {
    fontSize: '0.8rem',
    color: '#999',
    marginBottom: '10px'
  },
  loading: {
    textAlign: 'center',
    padding: '60px'
  }
};

export default AdminPanel;
